import React, { useState, useEffect } from 'react';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { login } from '../store/slices/authSlice';
import toast from 'react-hot-toast';

export default function Login() {
  const [username, setUsername] = useState('admin');
  const [password, setPassword] = useState('admin123');
  const [loading,  setLoading]  = useState(false);
  const [error,    setError]    = useState('');
  const dispatch = useDispatch();
  const navigate = useNavigate();

  // Clear ALL stored tokens when login page opens
  useEffect(() => {
    localStorage.clear();
    sessionStorage.clear();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!username || !password) { setError('Please enter username and password'); return; }

    setLoading(true);
    setError('');

    const res = await dispatch(login({ username: username.trim(), password }));

    if (login.fulfilled.match(res)) {
      toast.success('Login successful! Welcome 👋');
      navigate('/', { replace: true });
    } else {
      const msg = res.payload || 'Login failed';
      setError(msg);
      toast.error(msg);
    }
    setLoading(false);
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #1E1B4B 0%, #312E81 50%, #4C1D95 100%)',
      display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16
    }}>
      <div style={{
        background: '#fff', borderRadius: 20, padding: 40,
        width: 420, maxWidth: '100%',
        boxShadow: '0 32px 80px rgba(0,0,0,.3)'
      }}>
        {/* Logo */}
        <div style={{ textAlign: 'center', marginBottom: 32 }}>
          <div style={{
            width: 64, height: 64,
            background: 'linear-gradient(135deg, #7C3AED, #F59E0B)',
            borderRadius: 18, display: 'flex', alignItems: 'center',
            justifyContent: 'center', fontSize: 30,
            margin: '0 auto 14px', boxShadow: '0 8px 24px rgba(124,58,237,.4)'
          }}>🏫</div>
          <h1 style={{ fontSize: 24, fontWeight: 800, color: '#1E1B4B', margin: 0 }}>EduManage</h1>
          <p style={{ fontSize: 13, color: '#9CA3AF', marginTop: 4 }}>School Management System</p>
        </div>

        {/* Error box */}
        {error && (
          <div style={{
            padding: '12px 16px', background: '#FEF2F2',
            border: '1px solid #FECACA', borderRadius: 10,
            fontSize: 13, color: '#DC2626', marginBottom: 20,
            display: 'flex', alignItems: 'center', gap: 8
          }}>
            <span>⚠️</span> {error}
          </div>
        )}

        <form onSubmit={handleSubmit}>
          {/* Username */}
          <div style={{ marginBottom: 16 }}>
            <label style={{
              display: 'block', fontSize: 12, fontWeight: 700,
              color: '#374151', textTransform: 'uppercase',
              letterSpacing: '.06em', marginBottom: 7
            }}>Username</label>
            <input
              type="text"
              value={username}
              onChange={e => setUsername(e.target.value)}
              placeholder="Enter username"
              autoFocus
              style={{
                width: '100%', padding: '12px 16px',
                border: '2px solid #E5E7EB', borderRadius: 10,
                fontSize: 14, outline: 'none', fontFamily: 'inherit',
                transition: 'border-color .15s'
              }}
              onFocus={e => e.target.style.borderColor = '#7C3AED'}
              onBlur={e  => e.target.style.borderColor = '#E5E7EB'}
            />
          </div>

          {/* Password */}
          <div style={{ marginBottom: 24 }}>
            <label style={{
              display: 'block', fontSize: 12, fontWeight: 700,
              color: '#374151', textTransform: 'uppercase',
              letterSpacing: '.06em', marginBottom: 7
            }}>Password</label>
            <input
              type="password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              placeholder="Enter password"
              style={{
                width: '100%', padding: '12px 16px',
                border: '2px solid #E5E7EB', borderRadius: 10,
                fontSize: 14, outline: 'none', fontFamily: 'inherit',
                transition: 'border-color .15s'
              }}
              onFocus={e => e.target.style.borderColor = '#7C3AED'}
              onBlur={e  => e.target.style.borderColor = '#E5E7EB'}
            />
          </div>

          {/* Submit */}
          <button
            type="submit"
            disabled={loading}
            style={{
              width: '100%', padding: '14px',
              background: loading ? '#9CA3AF' : '#1E1B4B',
              color: '#fff', border: 'none', borderRadius: 12,
              fontSize: 15, fontWeight: 700,
              cursor: loading ? 'not-allowed' : 'pointer',
              transition: 'background .15s'
            }}
          >
            {loading ? '⏳ Signing in...' : 'Sign In →'}
          </button>
        </form>

        {/* Demo accounts */}
        <div style={{
          marginTop: 24, padding: 16,
          background: '#F9FAFB', borderRadius: 12,
          border: '1px dashed #D1D5DB'
        }}>
          <p style={{ fontSize: 11, fontWeight: 700, color: '#9CA3AF', textTransform: 'uppercase', letterSpacing: '.08em', marginBottom: 10 }}>
            Demo Accounts (password: admin123)
          </p>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            {[
              ['admin',      'Admin',       '#EDE9F8', '#4C1D95'],
              ['principal',  'Principal',   '#DBEAFE', '#1E40AF'],
              ['teacher1',   'Teacher',     '#D1FAE5', '#065F46'],
              ['accountant', 'Accountant',  '#FEF3C7', '#92400E'],
              ['parent1',    'Parent',      '#FCE7F3', '#9D174D'],
            ].map(([u, label, bg, color]) => (
              <button
                key={u}
                type="button"
                onClick={() => { setUsername(u); setPassword('admin123'); }}
                style={{
                  padding: '5px 14px', background: bg,
                  border: 'none', borderRadius: 20,
                  fontSize: 12, fontWeight: 600,
                  color, cursor: 'pointer'
                }}
              >
                {label}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
